// --- Lookup helpers ---

const discById = new Map(DISC_DATABASE.map((d) => [d.id, d]));
const discsByMfg = new Map<string, Disc[]>();
for (const d of DISC_DATABASE) {
  const list = discsByMfg.get(d.manufacturer) ?? [];
  list.push(d);
  discsByMfg.set(d.manufacturer, list);
}

export function getDiscById(id: string): Disc | undefined {
  return discById.get(id);
}

export function getDiscsByManufacturer(mfg: string): Disc[] {
  return discsByMfg.get(mfg) ?? [];
}

export function getAllManufacturers(): string[] {
  return [...discsByMfg.keys()].sort();
}

export function searchDiscs(query: string): Disc[] {
  if (!query.trim()) return DISC_DATABASE;
  const q = query.toLowerCase();
  return DISC_DATABASE.filter(
    (d) => d.name.toLowerCase().includes(q) || d.manufacturer.toLowerCase().includes(q)
  );
}
